using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController(IDocumentSummarizer summarizer) : ControllerBase
{
    /// <summary>
    /// Accepts document text and returns a concise extractive summary.
    /// </summary>
    [HttpPost]
    public ActionResult<SummarizationResponse> Summarize([FromBody] SummarizationRequest request)
    {
        var summary = summarizer.Summarize(request.DocumentText, request.MaxSentences);

        return Ok(new SummarizationResponse
        {
            Summary = summary,
            OriginalWordCount = request.DocumentText.Split((char[]?)null, StringSplitOptions.RemoveEmptyEntries).Length,
            SummaryWordCount = summary.Split((char[]?)null, StringSplitOptions.RemoveEmptyEntries).Length
        });
    }
}

